/**
 * Shared types for InstructionsLoaded (per-file) + SessionStart (whole-set)
 * instruction handlers.
 *
 * #2475: the real CC InstructionsLoaded event is single-file. Per-file
 * handlers accumulate state via the session-scoped state files below.
 * Whole-set handlers still consume `LoadedFile[]` — but the array is now
 * built by reading the rule set from disk at SessionStart
 * (see session-rules-audit.ts), not from a fabricated event payload.
 */

export interface LoadedFile {
  path: string;
  source?: string;
  byte_size?: number;
}

export interface DriftCache {
  version: '1.0';
  lastSession: string;
  fileHashes: Record<string, string>;
}

export interface ProjectSignal {
  check: () => boolean;
  ruleName: string;
  description: string;
}

/**
 * Session-scoped accumulator for token-budget-tracker (#2475).
 * Lives at <sessionTempDir>/instruction-budget.json.
 */
export interface InstructionBudgetState {
  version: '1.0';
  /** file path -> byte size, accumulated across per-file firings */
  files: Record<string, number>;
  /** budget warning already surfaced this session (warn once) */
  warned: boolean;
}

/**
 * Session-scoped accumulator for smart-suggestions (#2475).
 * Lives at <sessionTempDir>/loaded-instructions.json.
 */
export interface LoadedInstructionsState {
  version: '1.0';
  /** basenames of instruction files loaded so far this session */
  files: string[];
  /** current missing-rule suggestions (recomputed per firing) */
  suggestions: string[];
  /** suggestion message already surfaced this session (notify once) */
  notified: boolean;
}
